import { log, Vec3 } from "cc";
import { BaseState, newBottombarManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { eventManager } from "db://astarte-framework/Managers";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
import { Define, tools } from "db://astarte-framework/utilis";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";

export class CountMultState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "game state COUNT_MULT" );

        let plateInfoData = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].PlateQueue;
        let plateIdx = this.m_gameView.CurPlateIndex;
        if(plateIdx < plateInfoData.length )
        {
            let awardDataVec = plateInfoData[ plateIdx ].AwardDataVec ? plateInfoData[ plateIdx ].AwardDataVec : [];
            let explodeDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
            let targetDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
            //加入標靶消除範圍
            if(plateInfoData[plateIdx].TargetDataVec.length > 0)
            {
                for(let i = 0; i < plateInfoData[plateIdx].TargetDataVec.length; i++)
                {
                    let eliminatePos: number[] = [];
                    for(let pos of plateInfoData[plateIdx].TargetDataVec[i].EliminatePos)
                    {
                        eliminatePos.push(pos);
                    }

                    //標靶消除範圍
                    explodeDataVec.push( {
                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
                        EliminatePos: eliminatePos
                    } );

                    //標靶演出用
                    targetDataVec.push( {
                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
                        EliminatePos: [plateInfoData[plateIdx].TargetDataVec[i].Pos]
                    } );
                }
            }


            for ( let i = 0; i < awardDataVec.length; i++ )
            {
                if(awardDataVec[i].EliminatePos.length > 0)
                {
                    explodeDataVec.push( awardDataVec[ i ] );

                }
            }
            this.m_gameView.CurExplodeDataVec = explodeDataVec;


            //await this.m_gameView.EffectPlate.SymbolWinEffect(explodeDataVec);
            // 計算乘倍
            let promises: Promise<void>[] = [];
            this.m_gameView.PendingAwardResults = [];
            for ( let i = 0; i < awardDataVec.length; i++ )
            {
                let awardData : protocol.ar2pq9Proto.IAwardData[] = [];
                awardData.push(awardDataVec[i]);

                //贏分演出
                await this.m_gameView.EffectPlate.SymbolWinEffect(awardData);

                let col = Math.floor(awardDataVec[i].EliminatePos[0] / Game_Define.ROW);
                let isLeft = col < Game_Define.COL / 2;
                let pos0 = awardDataVec[i].EliminatePos[0];

                if (awardDataVec[i].Multiple > 1) {
                    // 1. 顯示 ODD 靜止不消失
                    let oddsNode = await this.m_gameView.EffectPlate.ShowStaticOdds(
                        pos0, awardDataVec[i].Odds.toString(), isLeft);

                    // 2. 乘倍飛入
                    let targetPos = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos0).getWorldPosition();
                    for(let pos of awardDataVec[i].EliminatePos)
                    {
                        promises.push( new Promise(
                            async ( resolve ) =>
                            {
                                eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM, pos, 
                                    this.m_gameView.EffectPlate.GetEffctNode(Game_Define.LAYERS.MULTI_FLY) );
                                let waitTime = this.m_gameView.IsHardStop ? 0 : 0.2;
                                await Define.Wait( this.m_gameView, waitTime );
                                eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET, pos, 
                                    targetPos, 0.5, 
                                    async ()=>
                                        {
                                            eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM, pos );
                                            resolve();
                                        }) ;
                            }
                        ) );
                    }
                    await Promise.all( promises ); 
                    promises = [];

                    // 3. 乘倍到達後更新為 Odds X Multiple → 往上飛消失
                    let formula = awardDataVec[i].Odds.toString() + "  X  " + awardDataVec[i].Multiple.toString();
                    await this.m_gameView.EffectPlate.UpdateStaticAndFlyUp(oddsNode, formula);
                }

                // 4. 暫存結果（EXPLODE 時顯示）
                let winDisplay = (awardDataVec[i].Win || awardDataVec[i].Odds || 0).toString();
                this.m_gameView.EffectPlate.AddPendingResult(pos0, winDisplay, isLeft);
                this.m_gameView.PendingAwardResults.push({
                    pos: pos0,
                    win: awardDataVec[i].Win || awardDataVec[i].Odds || 0,
                    fullResult: winDisplay,
                    isLeft: isLeft
                });

                log({roundWin: this.m_gameView.RoundWin, totalWin: this.m_gameView.SpinAck.TotalWin});
            }


            //標靶演出
            if(targetDataVec.length > 0)
            {
                const isExpanded = this.m_gameView.IsFreeGame && this.m_gameView.FreePickItems.indexOf(0) >= 0;
                await this.m_gameView.EffectPlate.PlayTargetExplodeEffect(
                    plateInfoData[plateIdx].TargetDataVec, isExpanded);
            }



            //await Promise.all( promises ); 
            /*
            for ( let i = 0; i < awardDataVec.length; i++ )
            {
                let winValue = awardDataVec[i].Odds.toString() + "  X  " + awardDataVec[i].Multiple.toString() + "  =  " + awardDataVec[i].Win.toString();
                let col = Math.floor(awardDataVec[i].EliminatePos[0] / Game_Define.ROW);
                let isLeft = col < Game_Define.COL / 2;
                await this.m_gameView.EffectPlate.ShowMultiplyFlyEffect(awardDataVec[i].EliminatePos[0], winValue, isLeft);
                // 計算消除部分的贏分
                this.m_gameView.RoundWin = tools.plus( this.m_gameView.RoundWin, awardDataVec[ i ].Win );

            }           
            newBottombarManager.SetWinValueWithCheck( {
                maxWin: this.m_gameView.SpinAck.TotalWin,
                value: tools.plus( this.m_gameView.RoundWin, this.m_gameView.Win ),
            } );*/

            stateManager.NextState( Game_Define.GameState.EXPLODE );
        }
        else
        {
            stateManager.NextState( Game_Define.GameState.EFFECT_START );
        }


    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

