273	    OnEvent(event: string, ...args: any[]) {
274	        switch (event) {
275	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER:
276	                if (this.ValidateSetMultiplierArgs(args)) {
