287	                    this.SetMultiplierList(args[0] as number[]);
288	                }
289	                break;
290	
291	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW:
292	                if (this.ValidateSetShowArgs(args)) {
293	                    this.SetShow(args[0] as number, args[1] as boolean);
294	                }
295	                break;
296	
297	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW:
298	                if (this.ValidateSetFrameShowArgs(args)) {
299	                    this.SetFrameShow(args[0] as number, args[1] as boolean);
300	                }
301	                break;
302	            case MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM:
303	                if (this.ValidatePopMulItemArgs(args)) {
304	                    this.PopMulItem(args[0] as number, args[1] as Node);
305	                }
306	                break;
