309	                    this.PushMulItem(args[0] as number);
310	                }
311	                break;
312	            case MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET:
313	                if (this.ValidateMulItemFlyToTargetArgs(args)) {
314	                    this.MulItemFlyToTarget(args[0] as number, args[1] as Vec3, args[2] as number, args[3] as () => void);
315	                }
