322	            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM:
323	                if (this.ValidateAddMultiplierArgs(args)) {
324	                    this.AddMultiplierWithAnim(args[0] as number, args[1] as () => void);
