328	                this.CheckMultiplierWithServer(
329	                    args[0] as protocol.ar2pq9Proto.IIntAry[],
330	                    args[1] as number[]
331	                );
332	                break;
333	            default:
334	                warn('[MultiplierBaseManager] OnEvent: 未知的事件', event);
335	        }
336	    }
