523	    /**
524	     * @ch 判斷指定 MultiplierBase 是否已達倍率上限
525	     * @param item 目標 MultiplierBase
526	     * @returns 已達上限為 true
527	     */
528	    private IsAtMaxMultiplier(item: MultiplierBase): boolean {
