530	    }
531	
532	    /**
533	     * @ch 指定索引的倍率加 1（index 為負數時設置全部）
534	     * @param index 目標 MultiplierBase 索引，負數表示全部
535	     */
536	    private AddMultiplier(index: number): void {
537	        if (index < 0) {
538	            this.AddAllMultiplier();
539	            return;
540	        }
541	        const item = this.GetMultiplierBase(index);
542	        if (!item) return;
543	        if (this.IsAtMaxMultiplier(item)) return;
544	        item.SetMultiplier(item.GetMultiplierIndex() + 1);
545	    }
546	
547	    /**
548	     * @ch 所有 MultiplierBase 的倍率加 1
549	     */
550	    private AddAllMultiplier(): void {
551	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
552	            warn('[MultiplierBaseManager] AddAllMultiplier: MultiplierBase 陣列未設置');
553	            return;
554	        }
555	        this.m_multiplierBases.forEach((item, i) => {
556	            if (!item) {
557	                warn(`[MultiplierBaseManager] AddAllMultiplier: 索引 ${i} 的 MultiplierBase 未設置`);
558	                return;
559	            }
560	            if (this.IsAtMaxMultiplier(item)) return;
561	            item.SetMultiplier(item.GetMultiplierIndex() + 1);
