565	    /**
566	     * @ch 播放加成動畫後指定索引的倍率加 1（index 為負數時設置全部）
567	     * @param index 目標 MultiplierBase 索引，負數表示全部
568	     * @param callback 動畫完成後的回調函數
569	     */
570	    private AddMultiplierWithAnim(index: number, callback?: () => void): void {
571	        if (index < 0) {
572	            this.AddAllMultiplierWithAnim(callback);
573	            return;
574	        }
575	        const item = this.GetMultiplierBase(index);
576	        if (!item) { if (callback) callback(); return; }
577	        if (this.IsAtMaxMultiplier(item)) { if (callback) callback(); return; }
578	        item.PlayUpgradeAndSetMultiplier(item.GetMultiplierIndex() + 1).then(() => {
579	            if (callback) callback();
580	        });
581	    }
