583	    /**
584	     * @ch 播放加成動畫後所有 MultiplierBase 的倍率加 1
585	     * @param callback 全部動畫完成後的回調函數
586	     */
587	    private AddAllMultiplierWithAnim(callback?: () => void): void {
588	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
589	            warn('[MultiplierBaseManager] AddAllMultiplierWithAnim: MultiplierBase 陣列未設置');
590	            if (callback) callback();
591	            return;
592	        }
593	        const promises: Promise<void>[] = [];
594	        this.m_multiplierBases.forEach((item, i) => {
595	            if (!item) {
596	                warn(`[MultiplierBaseManager] AddAllMultiplierWithAnim: 索引 ${i} 的 MultiplierBase 未設置`);
597	                return;
598	            }
599	            if (this.IsAtMaxMultiplier(item)) return;
600	            promises.push(item.PlayUpgradeAndSetMultiplier(item.GetMultiplierIndex() + 1));
601	        });
602	        Promise.all(promises).then(() => {
603	            if (callback) callback();
604	        });
605	    }
606	
607	    /**
608	     * @ch 回歸守衛：驗證被消除位置的乘倍底板當前 index 是否等於 Server 期望（BasePlateIndex）
609	     * 位置 index = col*ROW+row 對應 m_multiplierBases。Server 值會先夾到顯示上限再比對，
610	     * 避免高倍率被 clamp（SetMultiplier 內）造成假警報。不一致只 error log，不影響玩法
611	     * （同 SlotReels.CheckPlateInfo 風格）。
612	     * @param basePlateIndex Server 每位置底板絕對 index（[col].Data[row]）
613	     * @param positions 本盤被消除的位置（一維索引）
614	     */
615	    private CheckMultiplierWithServer(
616	        basePlateIndex: protocol.ar2pq9Proto.IIntAry[],
617	        positions: number[]
618	    ): void {
619	        if (!basePlateIndex || basePlateIndex.length === 0) return;
620	        if (!positions || positions.length === 0) return;
621	
622	        const errors: any[] = [];
623	        for (const pos of positions) {
624	            if (pos < 0 || pos >= this.m_multiplierBases.length) continue;
625	            const item = this.m_multiplierBases[pos];
626	            if (!item) continue;
627	
628	            const col = Math.floor(pos / Game_Define.ROW);
629	            const row = pos % Game_Define.ROW;
630	            const expected = basePlateIndex[col]?.Data?.[row];
631	            if (expected === null || expected === undefined) continue;
632	
633	            // Server 值夾到顯示上限再比（顯示本就 clamp，超限非錯誤）
634	            const expectedClamped = Math.min(expected, item.GetMaxMultiplierIndex());
635	            const actual = item.GetMultiplierIndex();
636	            if (actual !== expectedClamped) {
637	                errors.push({ pos, col, row, expected, expectedClamped, actual });
638	            }
639	        }
640	
641	        if (errors.length > 0) {
642	            error('[MultiplierBaseManager] 乘倍底板與 Server 期望值不一致:', JSON.stringify(errors));
643	        }
644	    }
645	    //#endregion Methods
646	
647	    //#region 測試功能
648	    /**
649	     * @ch 測試按鍵處理
650	     * - 數字鍵 1：設置索引 0 的倍率為 3
651	     * - 數字鍵 2：設置索引 0 的倍率為 6
652	     * - 數字鍵 3：設置所有倍率為 5
653	     * - 數字鍵 4：隱藏索引 0
654	     * - 數字鍵 5：顯示索引 0
655	     * - 數字鍵 6：批次設置倍率 [2, 5, 8]
656	     */
657	    private CheckTestKeyCode(event: EventKeyboard): void {
658	        switch (event.keyCode) {
659	            case KeyCode.DIGIT_1:
660	                log('[MultiplierBaseManager] 測試：設置索引 0 倍率Index為 3');
661	                this.SetMultiplier(0, 3);
662	                break;
663	
664	            case KeyCode.DIGIT_2:
665	                log('[MultiplierBaseManager] 測試：設置索引 0 倍率Index為 6');
666	                this.SetMultiplier(0, 6);
667	                break;
668	
669	            case KeyCode.DIGIT_3:
670	                log('[MultiplierBaseManager] 測試：設置所有倍率Index為 5');
671	                this.SetMultiplier(-1, 5);
672	                break;
673	
674	            case KeyCode.DIGIT_4:
675	                log('[MultiplierBaseManager] 測試：隱藏索引 0');
676	                this.SetShow(0, false);
677	                break;
678	
679	            case KeyCode.DIGIT_5:
680	                log('[MultiplierBaseManager] 測試：顯示索引 0');
681	                this.SetShow(0, true);
682	                break;
683	
684	            case KeyCode.DIGIT_6:
685	                log('[MultiplierBaseManager] 測試：批次設置倍率 [2, 5, 8]');
686	                this.SetMultiplierList([2, 5, 8]);
687	                break;
688	        }
689	    }
690	    //#endregion 測試功能
691	}
