import { _decorator, Component, error, log, warn, Node ,UIOpacity, Vec3, tween, sp} from 'cc';
import { SpriteChange } from '../Common/SpriteChange';
const { ccclass, property } = _decorator;
import { Common } from '../Common/Common';

@ccclass('MultiplierBase')
export class MultiplierBase extends Component {
    //#region Properties
    @property({
        type: SpriteChange,
        tooltip: "底框 SpriteChange"
    })
    private m_baseFrameSpriteChange: SpriteChange = null;

    @property({
        type: SpriteChange,
        tooltip: "乘數倍率 SpriteChange"
    })
    private m_multiplierSpriteChange: SpriteChange = null;
    //#endregion Properties

    //#region Variables
    /**@ch 倍率索引*/
    private m_multiplierIndex: number = 0;

    /**@ch 乘數倍率索引開始*/
    private readonly m_multiplierSpriteIndexStart: number = 2;

    @property({
        type: sp.Skeleton,
        tooltip: "升級 Spine 動畫"
    })
    private m_upgradeSpine: sp.Skeleton = null;

    /**@ch 底框倍率限制*/
    private readonly m_baseFrameMultiplierLimits: ReadonlyArray<number> = [2, 5, 8, 11, 16];
    //#endregion Variables

    //#region Methods
    /**
     * @ch 設置倍率索引
     * @param multiplierIndex 倍率索引
     */
    public SetMultiplier(multiplierIndex: number) {
        if (!this.m_baseFrameSpriteChange || !this.m_multiplierSpriteChange) {
            error(`[MultiplierBase] 底框或乘數倍率SpriteChange元件未設定`);
            return;
        }
        // 夾制到顯示上限，避免內部索引漂移到可顯示範圍之外
        const maxIndex = this.GetMaxMultiplierIndex();
        if (multiplierIndex > maxIndex) {
            warn(`[MultiplierBase] 倍率索引 ${multiplierIndex} 超過上限 ${maxIndex}，已夾制`);
            multiplierIndex = maxIndex;
        }
        this.m_multiplierIndex = multiplierIndex;

        const showMultiplier = multiplierIndex >= this.m_multiplierSpriteIndexStart;
        const showBaseFrame = multiplierIndex > 0;
        this.SetNodeActive(this.m_baseFrameSpriteChange.node, showBaseFrame);
        this.SetNodeActive(this.m_multiplierSpriteChange.node, showMultiplier);

        this.m_baseFrameSpriteChange.ChangeSpriteByIndex(this.GetBaseFrameIndex(multiplierIndex));
        if (showMultiplier) {
            this.m_multiplierSpriteChange.ChangeSpriteByIndex(multiplierIndex - this.m_multiplierSpriteIndexStart);
        }
    }

    /**
     * @ch 獲取倍率索引
     * @returns 倍率索引
     */
    public GetMultiplierIndex(): number {
        return this.m_multiplierIndex;
    }

    /**
     * @ch 取得倍率索引上限（可顯示的最大倍率索引）
     * @returns 最大倍率索引；乘數倍率 SpriteChange 未設定時回傳 0
     * @remarks 乘數圖以 (multiplierIndex - m_multiplierSpriteIndexStart) 取圖，故上限 = 圖片數量 + (起始值 - 1)
     */
    public GetMaxMultiplierIndex(): number {
        if (!this.m_multiplierSpriteChange) return 0;
        return this.m_multiplierSpriteChange.GetSpriteFrameCount() + this.m_multiplierSpriteIndexStart - 1;
    }

    /**@ch Spine skin 名稱對應表（index 0 = multiplierIndex 2）*/
    private static readonly UPGRADE_SKINS: ReadonlyArray<string> = [
        '2', '4', '8', '16', '32', '64', '128', '256', '512', '1024', '2048', '4096', '8192', '9999'
    ];

    /**
     * @ch 播放升級動畫後再設置倍率
     * @param multiplierIndex 新的倍率索引
     */
    public PlayUpgradeAndSetMultiplier(multiplierIndex: number): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!this.m_upgradeSpine || !this.m_upgradeSpine.skeletonData || multiplierIndex <= this.m_multiplierIndex) {
                this.SetMultiplier(multiplierIndex);
                resolve();
                return;
            }
            this.m_upgradeSpine.node.active = true;

            requestAnimationFrame(() => {
                try {
                    if (multiplierIndex >= this.m_multiplierSpriteIndexStart) {
                        const skinIdx = multiplierIndex - this.m_multiplierSpriteIndexStart;
                        if (skinIdx < MultiplierBase.UPGRADE_SKINS.length) {
                            this.m_upgradeSpine.setSkin(MultiplierBase.UPGRADE_SKINS[skinIdx]);
                        }
                    } else {
                        this.m_upgradeSpine.setSkin('DefaultSkin');
                    }
                    this.m_upgradeSpine.setAnimation(0, 'Upgrade', false);
                } catch (e) {
                    this.m_upgradeSpine.node.active = false;
                    this.SetMultiplier(multiplierIndex);
                    resolve();
                    return;
                }

                let resolved = false;
                const done = () => {
                    if (resolved) return;
                    resolved = true;
                    this.m_upgradeSpine.setCompleteListener(null);
                    this.m_upgradeSpine.node.active = false;
                    this.SetMultiplier(multiplierIndex);
                    resolve();
                };

                //this.m_upgradeSpine.setCompleteListener(done);
                this.scheduleOnce(done, 0.3);
            });
        });
    }

    /**
     * @ch 獲取底框索引
     * @param multiplierIndex 倍率索引
     * @returns 底框索引
     */
    private GetBaseFrameIndex(multiplierIndex: number): number {
        if (this.m_baseFrameMultiplierLimits.length === 0) {
            return 0;
        }
        for (let i = 0; i < this.m_baseFrameMultiplierLimits.length; i++) {
            if (multiplierIndex < this.m_baseFrameMultiplierLimits[i]) {
                return i;
            }
        }
        return this.m_baseFrameMultiplierLimits.length - 1;
    }

    /**
     * @ch 設置節點顯示狀態
     * @param node 節點
     * @param isActive 顯示狀態
     */
    private SetNodeActive( node: Node, isActive: boolean) {
        if (node && node.isValid) {
            node.active = isActive;
        }
    }

    /**
     * @ch 設置底框顯示狀態
     * @param isShow 顯示狀態
     */
    public SetFrameShow(isShow: boolean) {
        this.SetNodeActive(this.m_baseFrameSpriteChange.node, isShow);
    }

    /**
     * @ch 設置乘數倍率顯示狀態
     * @param isShow 顯示狀態
     */
    public SetMultiplierShow(isShow: boolean) {
        this.SetNodeActive(this.m_multiplierSpriteChange.node, isShow);
    }

    public SetMultiplierNodeToOtherLayer(parent: Node) {
        let isactive = this.m_multiplierSpriteChange.node.active;
        this.m_multiplierSpriteChange.node.setParent(parent,true);
        this.m_multiplierSpriteChange.node.getComponent(UIOpacity).opacity = 255;

    }

    public RecoverMultiplierNode(): void {
        this.m_multiplierSpriteChange.node.setParent(this.node,false);
        this.m_multiplierSpriteChange.node.setScale(1,1,1);
        this.m_multiplierSpriteChange.node.setPosition(0,0,0);
        this.m_multiplierSpriteChange.node.getComponent(UIOpacity).opacity = 128;
        this.m_multiplierSpriteChange.node.active = false;

    }

    public MulItemFlyToTarget(targetPos: Vec3, duration: number, callback: () => void): void {

        if(this.m_multiplierIndex >= this.m_multiplierSpriteIndexStart)
        {
            //Common.MoveTo(this.m_multiplierSpriteChange.node, this.m_multiplierSpriteChange.node.getWorldPosition(), targetPos, duration, callback);
            // 設定起始位置
            this.m_multiplierSpriteChange.node.setWorldPosition(this.m_multiplierSpriteChange.node.getWorldPosition());

            // 建立直線移動動畫
            tween(this.m_multiplierSpriteChange.node)
                .to(duration, {
                    worldPosition: targetPos
                },{easing: 'cubicOut'})
                .call(() => {
                    // 確保最終位置正確
                    this.m_multiplierSpriteChange.node.setWorldPosition(targetPos);

                    // 調用完成回調
                    if (callback) {
                        callback();
                    }
                })
                .start();
        }
        else
        {
            if (callback) {
                callback();
            }
        }
    }
    //#endregion Methods
}

