import { error, log, tween } from "cc";
import { BaseState, msgBoxManager, newBottombarManager, stateManager } from "db://astarte-framework/Managers";
import { Define, tools } from "db://astarte-framework/utilis";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { eventManager } from "db://astarte-framework/Managers";
import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CHARACTER_ANIM_NAME, CANNON_ANIM_NAME } from "../BSSpineCtrl";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";

export class ExplodeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    { 
        log( "game state EXPLODE" );
        let plateInfoData = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].PlateQueue;
        let plateIdx = this.m_gameView.CurPlateIndex;

        const plateInfo = plateInfoData[ plateIdx ];

        // 新流程①：不分懸賞令/非懸賞令/Wild，一次消除全部
        // 以盤面實際 symbol 逐格重建消除資料（去重 + 每格用真實 symbol，wild 格→Wild 的 Remove）
        let explodeDataVec = this.BuildUnifiedExplodeData( plateInfo?.PlateSymbol ?? [] );

        if(explodeDataVec.length == 0)
        {
            stateManager.NextState( Game_Define.GameState.WANTED_POSTER );
            return;
        }

        // 靜態消除
        /*if(isHasTarget == false)
        {
            this.m_gameView.SlotReels.Exlpode( explodeDataVec );
        }*/
        // 動態消除 & 角色及大砲表演
        let removeTime = this.m_gameView.IsHardStop ? 0 : 0.5; // 角色及大砲開始播放時間
        await Define.Wait( this.m_gameView, removeTime );
        /*
        tween( this.m_gameView.node )
            .delay( removeTime )
            .call( () =>
            {
                this.m_gameView.IsLockRotation = true;
                //this.m_gameView.CannonController.PlayAnimation( CANNON_ANIM_NAME.Symbol_Remove );
                //this.m_gameView.Pirate.PlayAnimation( CHARACTER_ANIM_NAME.Symbol_Remove );
                eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
                    CHARACTER_ANIM_NAME.Symbol_Remove, false,()=>{log('Symbol_Remove 動畫播放完成')});
                eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 
                    CANNON_ANIM_NAME.Symbol_Remove , false,
                    async ()=>{
                        log('S_Symbol_Remove 動畫播放完成')
                        await this.m_gameView.EffectPlate.ExplodeEffect( explodeDataVec, plateIdx );
                    });
                this.PlayComboSound( plateIdx );
            } )
            .start();*/



        this.m_gameView.IsLockRotation = true;
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
            CHARACTER_ANIM_NAME.Symbol_Remove, false, ()=>{log('Symbol_Remove 動畫播放完成')});
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 
            CANNON_ANIM_NAME.Symbol_Remove , false, ()=>{log('Symbol_Remove 動畫播放完成')  });
        this.PlayComboSound( plateIdx );

        let waitTime = this.m_gameView.IsHardStop ? 0 : 0.2;
        await Define.Wait( this.m_gameView, waitTime );

        this.m_gameView.IsLockRotation = false;
        await Promise.all([
            this.m_gameView.EffectPlate.ExplodeEffect( explodeDataVec, plateIdx ),
            this.m_gameView.EffectPlate.ShowPendingMultiplyResults()
        ]);
        this.m_gameView.SlotReels.Exlpode( explodeDataVec );

        // 更新 bottom bar
        if (this.m_gameView.PendingAwardResults.length > 0) {
            for (const pending of this.m_gameView.PendingAwardResults) {
                this.m_gameView.RoundWin = tools.plus(this.m_gameView.RoundWin, pending.win);
                newBottombarManager.SetWinValueWithCheck({
                    maxWin: this.m_gameView.SpinAck.TotalWin,
                    value: this.m_gameView.RoundWin,
                });
            }
            this.m_gameView.PendingAwardResults = [];
        }

        // 新流程②：被消除位置（含 wild）底板一起 +1（ADD），不分懸賞令
        // 懸賞令位置之後在 WantedPosterState 再 SET 到 Server 目標值（步驟④）
        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true );

        let upgradePromises: Promise<void>[] = [];
        for ( let data of explodeDataVec )
        {
            for ( let pos of data.EliminatePos )
            {
                upgradePromises.push( new Promise<void>( ( resolve ) => {
                    eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM, pos, resolve );
                }));
            }
        }
        await Promise.all( upgradePromises );



        await Define.Wait( this.m_gameView, 0.5 );

        stateManager.NextState( Game_Define.GameState.WANTED_POSTER );



    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }

    /**
     * @ch 新流程①：以盤面實際 symbol 逐格重建消除資料
     * 把 CurExplodeDataVec（非懸賞 + 懸賞 BaseSymbol + 標靶範圍）攤平成位置集合並去重，
     * 每格用 plateSymbol 的真實 symbol 分組（wild 格→Wild），避免共用格重複消除、
     * 並確保 wild 格播 Wild 的 Remove 而非 BaseSymbol。
     */
    private BuildUnifiedExplodeData(
        plateSymbol: protocol.ar2pq9Proto.IColumn[]
    ): protocol.ar2pq9Proto.IAwardData[]
    {
        const posSet = new Set<number>();
        for ( const data of this.m_gameView.CurExplodeDataVec )
        {
            for ( const pos of data.EliminatePos )
            {
                posSet.add( pos );
            }
        }

        const bySymbol = new Map<number, number[]>();
        for ( const pos of posSet )
        {
            const col = Math.floor( pos / Game_Define.ROW );
            const row = pos % Game_Define.ROW;
            const sym = plateSymbol?.[ col ]?.Col?.[ row ] ?? 0;
            if ( !bySymbol.has( sym ) )
            {
                bySymbol.set( sym, [] );
            }
            bySymbol.get( sym )!.push( pos );
        }

        const result: protocol.ar2pq9Proto.IAwardData[] = [];
        bySymbol.forEach( ( eliminatePos, symbol ) =>
        {
            result.push( { Symbol: symbol, EliminatePos: eliminatePos } );
        } );
        return result;
    }

    private PlayComboSound( comboIdx: number )
    {
        // 第三消開始播
        /*
        if ( comboIdx == 2 )
        {
            soundManager.Play( Game_Define.AudioClips.Pirate_01 );
        }
        else if ( comboIdx == 3 )
        {
            soundManager.Play( Game_Define.AudioClips.Pirate_02 );
        }
        else if ( comboIdx == 5 )
        {
            soundManager.Play( Game_Define.AudioClips.Pirate_03 );
        }
        */
    }
}

